module SR_Latch (  
    input wire Invalid_S,  
    input wire R,  
    output reg Q,  
    output reg Qn  
);  
    always @ (Invalid_S or R) begin  
        if (Invalid_S && !R) begin  
            Q = 1;  
            Qn = 0;  
        end else if (!Invalid_S && R) begin  
            Q = 0;  
            Qn = 1;  
        end else if (!Invalid_S && !R) begin  
            Q = Q;  // Hold state  
            Qn = ~Q;  
        end else begin  
            Q = 1'bx;  // Invalid state  
            Qn = 1'bx;  
        end  
    end  
endmodule
